public class CommandInjectionFixed {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = br.readLine().trim(); // Trim any leading or trailing whitespace

            // Validate the input command to allow only specific characters or commands
            if (!command.matches("[a-zA-Z0-9_-]+")) {
                throw new IllegalArgumentException("Invalid command format");
            }

            Process process = Runtime.getRuntime().exec("ls " + command);

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            process.waitFor();
        } catch (IOException | InterruptedException | IllegalArgumentException e) {
            e.printStackTrace();
        }
    }
}

